func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	var result []map[string]interface{}

	// Define a timeout for each script execution to prevent DoS via infinite loops
	const scriptTimeout = 100 * time.Millisecond

	for _, item := range items {
		// Create a deep copy to prevent the script from modifying the original data
		itemCopy := deepCopyMap(item)

		vm := otto.New()

		// Set up interrupt channel to halt execution if it takes too long
		vm.Interrupt = make(chan func(), 1)
		done := make(chan struct{})

		// Start timeout goroutine
		go func() {
