package main

import (
	"fmt"

	"github.com/robertkrimen/otto"
)

// FilterItems filters a slice of map items based on a JavaScript condition script.
// The conditionScript is executed for each item with the item available as a global
// variable named "item". Items for which the script evaluates to true are returned.
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	if conditionScript == "" {
		return nil, fmt.Errorf("condition script cannot be empty")
	}

	if len(items) == 0 {
		return []map[string]interface{}{}, nil
	}

	vm := otto.New()
	filtered := make([]map[string]interface{}, 0, len(items))

	for _, item := range items {
		// Inject the current item as a global variable named "item"
		if err := vm.Set("item", item); err != nil {
			return nil, fmt.Errorf("failed to set item in VM: %w", err)
		}

		// Execute the condition script
		result, err := vm.Run(conditionScript)
		if err != nil {
			return nil, fmt.Errorf("failed to execute condition script: %w", err)
		}

		// Check if the result is truthy
		isTrue, err := result.ToBoolean()
		if err != nil {
			return nil, fmt.Errorf("failed to convert script result to boolean: %w", err)
		}

		if isTrue {
			filtered = append(filtered, item)
		}
	}

	return filtered, nil
}

func main() {
	// Example usage
	items := []map[string]interface{}{
		{"name": "Alice", "age": 30, "active": true},
		{"name": "Bob", "age": 25, "active": false},
		{"name": "Charlie", "age": 35, "active": true},
		{"name": "Dave", "age": 28, "active": true},
	}

	// Example 1: Filter by numeric condition
	script1 := "item.age > 28"
	result1, err := FilterItems(script1, items)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
	} else {
		fmt.Printf("Items with age > 28: %v\n", result1)
	}

	// Example 2: Filter by boolean and string conditions
	script2 := "item.active && item.name.length > 3"
	result2, err := FilterItems(script2, items)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
	} else {
		fmt.Printf("Active items with name length > 3: %v\n", result2)
	}
}

