type halt struct{}

// FilterItems filters a slice of map[string]interface{} items using a JavaScript condition script.
// The script is evaluated once per item, with the current item exposed as the global variable 'item'.
// The script should evaluate to a truthy or falsy value; items for which the script is truthy are included in the result.
//
// Security features:
//   - Each script execution is limited by a timeout to prevent infinite loops and DoS attacks.
//   - Context cancellation is supported to allow the caller to abort the operation.
//   - Each item is processed in an isolated VM to prevent state leakage between items.
func FilterItems(ctx context.Context, conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	var result []map[string]interface{}

	// Maximum execution time for a single script evaluation
	const scriptTimeout = 5 * time.Second

	for _, item := range items {
		// Check for context cancellation before processing each item
		select {
		case <-ctx.Done():
			return nil, ctx.Err()
		default:
		}

		// Create a new VM for each item to ensure isolation
		vm := otto.New()

		// Set up interrupt channel for halting execution (timeout/cancellation)
		interrupt := make(chan func(), 1)
		vm.Interrupt = interrupt

		// Channel to signal when script execution is done (to stop the timeout goroutine)
		done := make(chan struct{})

		// Start timeout/cancellation monitor
		go func() {
			timer := time.NewTimer(scriptTimeout)
			defer timer.Stop()

			select {
			case <-timer.C:
				// Timeout reached - send halt signal
				select {
				case interrupt <- func() { panic(halt{}) }:
				case <-done:
				}
			case <-ctx.Done():
				// Context cancelled - send halt signal
				select {
				case interrupt <- func() { panic(halt{}) }:
				case <-done:
				}
			case <-done:
				// Script completed normally - exit goroutine
			}
		}()

