		if err := vm.Set("item", item); err != nil {
			close(done)
			return nil, err
		}

		// Run the condition script
		value, err := vm.Run(conditionScript)

		// Signal that execution is done (stops the timeout goroutine)
		close(done)

		if err != nil {
			// Check if this was a timeout/interrupt
			if _, ok := err.(halt); ok {
				return nil, errors.New("script execution timeout or interrupted")
			}
			return nil, err
		}

		// Convert result to boolean using JavaScript truthiness
		boolResult, err := value.ToBoolean()
		if err != nil {
			return nil, err
		}

