package main

import (
	"fmt"
	"github.com/robertkrimen/otto"
)

// FilterItems filters a slice of maps based on a JavaScript condition script.
// The script is executed for each item with the item available as a global variable named "item".
// Items for which the script evaluates to true (or truthy) are included in the returned slice.
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	if len(items) == 0 {
		return []map[string]interface{}{}, nil
	}

	// Create a new Otto VM
	vm := otto.New()

	// Compile the script once for reuse across all items
	compiledScript, err := vm.Compile("", conditionScript)
	if err != nil {
		return nil, fmt.Errorf("failed to compile condition script: %w", err)
	}

	// Pre-allocate result slice with capacity of input
	filtered := make([]map[string]interface{}, 0, len(items))

	for _, item := range items {
		// Inject the current item as a global variable named "item"
		if err := vm.Set("item", item); err != nil {
			return nil, fmt.Errorf("failed to set item variable: %w", err)
		}

		// Execute the compiled script
		result, err := vm.Run(compiledScript)
		if err != nil {
			return nil, fmt.Errorf("failed to execute script for item %v: %w", item, err)
		}

		// Convert result to boolean
		isTrue, err := result.ToBoolean()
		if err != nil {
			return nil, fmt.Errorf("failed to convert script result to boolean for item %v: %w", item, err)
		}

		// Include item if condition evaluates to true
		if isTrue {
			filtered = append(filtered, item)
		}
	}

	return filtered, nil
}

func main() {
	// Example demonstration of FilterItems
	items := []map[string]interface{}{
		{"name": "Alice", "age": 30, "active": true},
		{"name": "Bob", "age": 25, "active": false},
		{"name": "Charlie", "age": 35, "active": true},
		{"name": "Diana", "age": 28, "active": true},
	}

	// Example 1: Filter by age
	script1 := `item.age > 28`
	result1, err := FilterItems(script1, items)
	if err != nil {
		fmt.Printf("Error in script1: %v\n", err)
		return
	}
	fmt.Printf("Items with age > 28: %v\n", result1)

	// Example 2: Filter by multiple conditions
	script2 := `item.active === true && item.name.length > 4`
	result2, err := FilterItems(script2, items)
	if err != nil {
		fmt.Printf("Error in script2: %v\n", err)
		return
	}
	fmt.Printf("Active items with name length > 4: %v\n", result2)

	// Example 3: Filter with arithmetic
	script3 := `(item.age % 2) === 0`
	result3, err := FilterItems(script3, items)
	if err != nil {
		fmt.Printf("Error in script3: %v\n", err)
		return
	}
	fmt.Printf("Items with even age: %v\n", result3)
}

